class AlertsWidget extends HTMLElement{constructor(){super();this.attachShadow({mode: 'open'});this.alerts=[];this.maxAlerts=10;}static get observedAttributes(){return ['title','max-items','filter'];}connectedCallback(){this.render();this.loadAlerts();}attributeChangedCallback(){this.render();}async loadAlerts(){this.alerts=[{id: 1,type: 'critical',title: 'Server Overload',message: 'CPU usage exceeded 90% in last 5 minutes',timestamp: new Date().toISOString(),dismissed: false},{id: 2,type: 'warning',title: 'Low Storage',message: 'Disk space below 15% on primary server',timestamp: new Date().toISOString(),dismissed: false},{id: 3,type: 'info',title: 'Backup Completed',message: 'Daily backup completed successfully',timestamp: new Date().toISOString(),dismissed: false},{id: 4,type: 'success',title: 'Deployment Success',message: 'Production deployment v2.4.1 completed',timestamp: new Date().toISOString(),dismissed: false},{id: 5,type: 'warning',title: 'API Rate Limit',message: 'Approaching rate limit threshold(85%)',timestamp: new Date().toISOString(),dismissed: false}];this.renderAlerts();}dismissAlert(alertId){const alertIndex=this.alerts.findIndex(a=>a.id===alertId);if(alertIndex!==-1){this.alerts[alertIndex].dismissed=true;this.alerts=this.alerts.filter(a=>!a.dismissed);this.renderAlerts();this.showToast('Alert dismissed','info');}}dismissAll(){this.alerts=[];this.renderAlerts();this.showToast('All alerts dismissed','info');}showToast(message,type='info'){const toast=document.createElement('div');toast.className=`toast toast-${type}`;toast.textContent=message;document.body.appendChild(toast);setTimeout(()=>toast.remove(),3000);}getTypeConfig(type){const config={critical:{icon: 'error',color: '#ff1744',bg: 'rgba(255,23,68,0.1)',border: 'rgba(255,23,68,0.3)'},warning:{icon: 'warning',color: '#ff9100',bg: 'rgba(255,145,0,0.1)',border: 'rgba(255,145,0,0.3)'},info:{icon: 'info',color: '#00e5ff',bg: 'rgba(0,229,255,0.1)',border: 'rgba(0,229,255,0.3)'},success:{icon: 'check_circle',color: '#00e676',bg: 'rgba(0,230,118,0.1)',border: 'rgba(0,230,118,0.3)'}};return config[type]||config.info;}formatTime(isoString){const date=new Date(isoString);const now=new Date();const diff=now-date;const minutes=Math.floor(diff/60000);const hours=Math.floor(diff/3600000);if(minutes<1)return 'Just now';if(minutes<60)return `${minutes}m ago`;if(hours<24)return `${hours}h ago`;return date.toLocaleDateString('vi-VN');}renderAlerts(){const container=this.shadowRoot.getElementById('alerts-container');if(!container)return;const filter=this.getAttribute('filter')||'all';let filteredAlerts=this.alerts;if(filter==='critical'){filteredAlerts=this.alerts.filter(a=>a.type==='critical');}else if(filter==='warning'){filteredAlerts=this.alerts.filter(a=>a.type==='warning');}if(filteredAlerts.length===0){container.innerHTML=`<div class="alerts-empty"><span class="material-symbols-outlined">check_circle</span><p>No alerts to display</p></div>`;return;}container.innerHTML=filteredAlerts.map(alert=>{const config=this.getTypeConfig(alert.type);return `<div class="alert-item alert-${alert.type}" data-alert-id="${alert.id}"><div class="alert-icon" style="background: ${config.bg};border-color: ${config.border};"><span class="material-symbols-outlined" style="color: ${config.color}">${config.icon}</span></div><div class="alert-content"><div class="alert-header"><h4 class="alert-title" style="color: ${config.color}">${alert.title}</h4><span class="alert-time">${this.formatTime(alert.timestamp)}</span></div><p class="alert-message">${alert.message}</p></div><button class="alert-dismiss" onclick="window.dispatchEvent(new CustomEvent('dismiss-alert',{detail: ${alert.id}}))" title="Dismiss"><span class="material-symbols-outlined">close</span></button></div>`;}).join('');this.shadowRoot.querySelectorAll('.alert-dismiss').forEach(btn=>{btn.addEventListener('click',(e)=>{const alertId=parseInt(e.currentTarget.closest('.alert-item').dataset.alertId);this.dismissAlert(alertId);});});}render(){const title=this.getAttribute('title')||'System Alerts';const maxItems=this.getAttribute('max-items')||this.maxAlerts;this.shadowRoot.innerHTML=`<style>:host{display: block;}.alerts-widget{background: rgba(255,255,255,0.05);backdrop-filter: blur(10px);border-radius: 16px;padding: 24px;border: 1px solid rgba(255,255,255,0.1);}.alerts-header{display: flex;justify-content: space-between;align-items: center;margin-bottom: 20px;}.alerts-title{font-size: 18px;font-weight: 600;color: #ffffff;display: flex;align-items: center;gap: 8px;}.alerts-title .material-symbols-outlined{color: #ff9100;}.alerts-actions{display: flex;gap: 8px;}.btn-filter{padding: 6px 12px;border-radius: 20px;border: 1px solid rgba(255,255,255,0.2);background: rgba(255,255,255,0.05);color: rgba(255,255,255,0.7);font-size: 12px;cursor: pointer;transition: all 0.2s ease;}.btn-filter:hover,.btn-filter.active{background: rgba(255,255,255,0.1);color: #ffffff;border-color: rgba(255,255,255,0.4);}.btn-filter.active{background: linear-gradient(135deg,#ff9100,#ff6d00);color: #000;border-color: transparent;}.btn-dismiss-all{padding: 6px 12px;border-radius: 20px;border: none;background: rgba(255,23,68,0.2);color: #ff1744;font-size: 12px;cursor: pointer;transition: all 0.2s ease;}.btn-dismiss-all:hover{background: rgba(255,23,68,0.3);}#alerts-container{display: flex;flex-direction: column;gap: 12px;}.alert-item{display: flex;align-items: flex-start;gap: 12px;padding: 14px;border-radius: 12px;background: rgba(255,255,255,0.03);border: 1px solid rgba(255,255,255,0.08);transition: all 0.3s ease;animation: alertSlideIn 0.4s ease forwards;}.alert-item:hover{transform: translateX(4px);background: rgba(255,255,255,0.06);}@keyframes alertSlideIn{from{opacity: 0;transform: translateX(-20px);}to{opacity: 1;transform: translateX(0);}}.alert-icon{width: 40px;height: 40px;border-radius: 10px;display: flex;align-items: center;justify-content: center;flex-shrink: 0;}.alert-icon .material-symbols-outlined{font-size: 20px;}.alert-content{flex: 1;min-width: 0;}.alert-header{display: flex;justify-content: space-between;align-items: center;margin-bottom: 4px;}.alert-title{font-size: 14px;font-weight: 600;margin: 0;}.alert-time{font-size: 11px;color: rgba(255,255,255,0.5);flex-shrink: 0;}.alert-message{font-size: 13px;color: rgba(255,255,255,0.7);margin: 0;line-height: 1.5;}.alert-dismiss{width: 28px;height: 28px;border-radius: 50%;border: none;background: rgba(255,255,255,0.1);color: rgba(255,255,255,0.6);cursor: pointer;display: flex;align-items: center;justify-content: center;transition: all 0.2s ease;flex-shrink: 0;}.alert-dismiss:hover{background: rgba(255,255,255,0.2);color: #ffffff;}.alert-dismiss .material-symbols-outlined{font-size: 16px;}.alerts-empty{display: flex;flex-direction: column;align-items: center;justify-content: center;padding: 40px;color: rgba(255,255,255,0.5);}.alerts-empty .material-symbols-outlined{font-size: 48px;color: #00e676;margin-bottom: 12px;}.alerts-empty p{margin: 0;font-size: 14px;}.alert-count{background: rgba(255,23,68,0.2);color: #ff1744;padding: 2px 8px;border-radius: 12px;font-size: 12px;font-weight: 600;}.toast{position: fixed;bottom: 20px;right: 20px;padding: 12px 20px;border-radius: 8px;color: #ffffff;font-size: 14px;z-index: 10000;animation: toastSlideIn 0.3s ease forwards;}.toast-info{background: linear-gradient(135deg,#00e5ff,#00b8d4);color: #000;}.toast-success{background: linear-gradient(135deg,#00e676,#00c853);color: #000;}.toast-warning{background: linear-gradient(135deg,#ff9100,#ff6d00);color: #000;}.toast-error{background: linear-gradient(135deg,#ff1744,#d50000);color: #ffffff;}@keyframes toastSlideIn{from{transform: translateX(100%);opacity: 0;}to{transform: translateX(0);opacity: 1;}}@media(max-width: 768px){.alerts-widget{padding: 16px;}.alert-item{padding: 12px;}.alert-icon{width: 36px;height: 36px;}}</style><div class="alerts-widget"><div class="alerts-header"><h3 class="alerts-title"><span class="material-symbols-outlined">notifications_active</span>${title}<span class="alert-count">${this.alerts.filter(a=>!a.dismissed).length}</span></h3><div class="alerts-actions"><button class="btn-filter active" data-filter="all">All</button><button class="btn-filter" data-filter="critical">Critical</button><button class="btn-filter" data-filter="warning">Warning</button><button class="btn-dismiss-all" onclick="window.dispatchEvent(new CustomEvent('dismiss-all-alerts'))">Dismiss All</button></div></div><div id="alerts-container"><div class="alerts-loading"><div class="loading-spinner"></div><span>Loading alerts...</span></div></div></div>`;setTimeout(()=>{this.shadowRoot.querySelectorAll('.btn-filter').forEach(btn=>{btn.addEventListener('click',(e)=>{this.shadowRoot.querySelectorAll('.btn-filter').forEach(b=>b.classList.remove('active'));e.target.classList.add('active');this.setAttribute('filter',e.target.dataset.filter);this.renderAlerts();});});this.shadowRoot.querySelector('.btn-dismiss-all')?.addEventListener('click',()=>{this.dismissAll();});},0);}}customElements.define('alerts-widget',AlertsWidget);